head.script:
// Apply theme and keycolor immediately on page load to avoid flashing
(function () {
  const savedTheme = localStorage.getItem('theme') || 'dark';
  const savedColor = localStorage.getItem('themeColor') || '#ff5722';
  const savedColor2 = localStorage.getItem('themeColor2') || '#03a9f4';

  if (savedTheme === 'dark') {
    document.documentElement.classList.add('dark');
  } else {
    document.documentElement.classList.remove('dark');
  }

  function hexToRgba(hex, alpha = 1) {
    const r = parseInt(hex.slice(1, 3), 16);
    const g = parseInt(hex.slice(3, 5), 16);
    const b = parseInt(hex.slice(5, 7), 16);
    return `rgba(${r}, ${g}, ${b}, ${alpha})`;
  }

  document.documentElement.style.setProperty('--keycolor', savedColor);
  document.documentElement.style.setProperty('--keycolor-opacity', hexToRgba(savedColor, 0.3));

  document.documentElement.style.setProperty('--keycolor2', savedColor2);
  document.documentElement.style.setProperty('--keycolor2-opacity', hexToRgba(savedColor2, 0.3));
})();

