</Group>

<Group description="Theme Header" selector=".head-container">
  <Variable name="head.background" description="Header fixed" type="color" default="#0a0c0f"  value="#0f0b0a"/>
  <Variable name="head.title.color" description="Header Font color" type="color" default="#ffffff"  value="#ffffff"/>
  <Variable name="head.title.hover" description="Header hover color hover" type="color" default="#00be06"  value="#6600be"/>
