  <Variable name="menu.title.color" description="Header menu link" type="color" default="#a9a9ac"  value="#acaba9"/>
</Group>

<Group description="Theme Label" selector=".entry-label,.slider-best">
  <Variable name="label" description="Label left Background" type="color" default="#00d639"  value="#a500d6"/>
  <Variable name="label2" description="Label right Background" type="color" default="#00c234"  value="#9600c2"/>
  <Variable name="label.button" description="Label button hover" type="color" default="#48d16c"  value="#b148d1"/>
  <Variable name="label.text" description="Label Font color" type="color" default="#ffffff"  value="#ffffff"/>
</Group>

<Group description="Blog title" selector=".entry-title">
  <Variable name="posts.title.color" description="Font color" type="color" default="#ffffff"  value="#ffffff"/>
  <Variable name="posts.title.hover" description="Font color hover" type="color" default="#1cc749"  value="#9f1cc7"/>
  <Variable name="posts.button.color" description="Button background" type="color" default="#2d2f34"  value="#342f2d"/>
  <Variable name="posts.button.hover" description="Button hover" type="color" default="#56575b"  value="#5b5856"/>
</Group>

<Group description="Blog pager" selector=".blog-pager">
  <Variable name="load.color" description="Background color" type="color" default="#2d2f34"  value="#342f2d"/>
  <Variable name="load.hover" description="Hover color" type="color" default="#37383d"  value="#3d3937"/>
</Group>

<Group description="Theme Footer" selector="div.footer-wrapper">
  <Variable name="background.footer" description="Background footer color" type="color" default="#0a0c0f" value="#0f0b0a"/>
  <Variable name="border.footer" description="Border footer color" type="color" default="#2d2f34"  value="#342f2d"/>
  <Variable name="line.footer" description="Line footer color" type="color" default="#333333"  value="#333333"/>
  <Variable name="footer.button" description="Button footer color" type="color" default="#23252b"  value="#2b2523"/>
  <Variable name="footer.text" description="Font footer color" type="color" default="#dddddd"  value="#dddddd"/>
  <Variable name="post.title.footer" description="Font link color" type="color" default="#999999"  value="#999999"/>
  <Variable name="post.footer.hover" description="Font link hover" type="color" default="#1cc749"  value="#9f1cc7"/>
  <Variable name="post.footer.copyright" description="Font copyright" type="color" default="#9b9b9b"  value="#9b9b9b"/>
</Group>

<Variable name="body.background.color" description="Comments Background" hideEditor="true" type="color" default="transparent"  value="rgba(0,0,0,0)"/>
<Variable name="body.title.color" description="Comments Color" hideEditor="true" type="color" default="#1cc749" value="#9f1cc7"/>
<Variable name="body.text.color" description="Comments Text Color" hideEditor="true" type="color" default="$(posts.title.color)"  value="#ffffff"/>
<Variable name="body.link.color" description="Comments Link Color" hideEditor="true" type="color" default="#1cc749"  value="#9f1cc7"/>
<Variable name="body.text.font" description="Comments Font 1" hideEditor="true" type="font" default="normal 400 15px roboto, Arial, sans-serif !important"  value="normal 400 15px roboto, Arial, sans-serif !important"/>
<Variable name="body.action.font.large" description="Comments Font 2" hideEditor="true" type="font" default="normal 700 15px roboto, Arial, sans-serif !important"  value="normal 700 15px roboto, Arial, sans-serif !important"/>
*/

