th:0;height:0;border-left:4px solid transparent;border-top:4px solid white;border-right:4px solid transparent}#main-menu #LinkList2 a:hover .down{border-bottom:4px solid var(--head-border-hover)}#main-menu #LinkList2:hover .down{border-right:4px solid transparent;border-bottom:4px solid white;border-left:4px solid transparent;border-top:0}#LinkList2 .menu-drop:after{display:block;box-sizing:border-box;content:"";height:12px;width:12px;position:absolute;z-index:-1;top:-1px;left:50%;transform:translate(-50%,-50%) rotate(45deg);background-color:var(--menu-background);border-left:1px solid rgba(255,255,255,0.25);border-top:1px solid rgba(255,255,255,0.25);border-radius:4px 0 0}#LinkList2 .menu-drop{display:none;position:absolute;top:59px;left:50%;transform:translate(-50%);border-radius:4px;background:var(--menu-background);border:1px solid var(--line-footer-m);box-sizing:border-box;min-height:0;padding:8px 0}#main-menu #LinkList2:hover .menu-drop{display:block}#LinkList2 .drop-link{margin:0;text-align:center;font-size:14px;width:180px;height:44px;line-height:44px;display:block;color:var(--menu-link-color);cursor:pointer}.menu-drop .drop-link:hover{background:var(--bg-trans)}#head-right{position:absolute;right:56px;display:flex;-webkit-box-align:center;align-items:center}.menu-grid{display:flex;margin:0 24px}.menu-grid .icon-link{text-align:center;width:80px;min-width:80px}.btn-head{display:flex;-webkit-box-align:center;align-items:center;-webkit-box-pack:center;justify-content:center;position:relative}.btn-head a{white-space: nowrap;overflow: hidden;text-overflow: ellipsis;color:var(--bg-label-text);background:var(--keycolor);display:flex;-webkit-box-align:center;align-items:center;-webkit-box-pack:center;justify-content:center;outline:0;padding:0 12px;box-sizing:border-box;height:34px;border-radius:4px}.btn-head svg{margin-right:4px;width:20px;height:20px}.BlogSearch *{outline:0}.head-widget .BlogSearch{width:240px;cursor:pointer}.BlogSearch .widget-content{position:re