@media(min-width:1024px){.slider-lab,.slider-best{font-size:14px;height:24px}}
.top-banner {
position: absolute;
bottom: 0;
left: 0;
z-index: 10;
color: #fff;
font-size: 14px;
font-weight: bold;
padding: 4px 8px 4px 10px;
pointer-events: none;
background: linear-gradient(
to top right,
rgba(0, 0, 0, 0.6) 0%,
rgba(0, 0, 0, 0.5) 30%,
rgba(0, 0, 0, 0.3) 60%,
rgba(0, 0, 0, 0.1) 85%,
rgba(0, 0, 0, 0) 100%
);
}
/* Optional rank gradients with smoother fades */
.rank-0 {
background: linear-gradient(
to top right,
rgba(255, 215, 0, 0.6) 0%,
rgba(255, 159, 0, 0.4) 40%,
rgba(247, 68, 68, 0.2) 75%,
rgba(247, 68, 68, 0) 100%
);
}
.rank-1 {
background: linear-gradient(
to top right,
rgba(66, 165, 245, 0.6) 0%,
rgba(22, 134, 255, 0.4) 40%,
rgba(15, 1, 139, 0.2) 75%,
rgba(15, 1, 139, 0) 100%
);
}
.rank-2 {
background: linear-gradient(
to top right,
rgba(9, 244, 81, 0.6) 0%,
rgba(51, 166, 94, 0.4) 40%,
rgba(27, 104, 42, 0.2) 75%,
rgba(27, 104, 42, 0) 100%
);
}
.rank-default {
background: linear-gradient(
to top right,
rgba(68, 68, 68, 0.6) 0%,
rgba(68, 68, 68, 0.4) 40%,
rgba(68, 68, 68, 0.2) 75%,
rgba(68, 68, 68, 0) 100%
);
}
/* Desktop adjustments */
@media screen and (min-width: 1024px) {
.top-banner {
font-size: 16px;
padding: 6px 10px;
}
}
