r:#ccc}.zlabel-year{color:#fff}.zlabel-status{color:lightgrey;font-size:14px}.zlabel-rated{color:#c10202!important}.zmeta-row{margin:5px 0}.zlabel-type{font-size:14px;color:var(--keycolor)}#live-search-dropdown ul li .text-container .zmeta-row,#live-search-dropdown ul li .text-container .zlabel-stats{white-space:nowrap;overflow:hidden;text-overflow:ellipsis}.separator{color:#5c5c5c8c}li a.view-all-results{font-weight:normal;justify-content:center}
