.browse-modal{display:none}@media(max-width:768px){.browse-modal{position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(20,20,20,1);z-index:9999;display:none;overflow-y:auto;padding:12px 20px 20px 20px;box-sizing:border-box}.browse-modal.active{display:block}.browse-header{display:flex;align-items:center;gap:10px;height:10px;width:200px;color:#fff}.browse-close{font-size:18px;cursor:pointer;color:#fff;position:static}.browse-close i{display:inline-block;vertical-align:middle;line-height:1.5;font-size:18px}.browse-title{font-size:18px;font-weight:700;margin:0}.browse-filters{display:flex;flex-wrap:wrap;gap:8px;align-items:center;justify-content:flex-start;position:sticky;top:-12px;width:100%;background-color:rgba(20,20,20,1);padding-top:15px;padding-bottom:12px;z-index:10}.browse-filters input,.browse-filters button,.browse-filters select{box-sizing:border-box}.browse-search-wrapper{flex:1 1 100%;max-width:100%;min-width:auto;position:relative}.browse-search-wrapper input{width:100%;padding:8px 40px 8px 12px;border:none;border-radius:6px;background-color:#181c25;color:#fafafa}.browse-search-wrapper .bi-search{position:absolute;right:12px;top:50%;transform:translateY(-50%);color:#94a3b8;pointer-events:none}.browse-dropdown{flex:1 1 calc(25% - 7.5px);min-width:0;position:relative;box-sizing:border-box;display:inline-block}.dropdown-btns{display:flex;flex-wrap:wrap;width:100%;gap:5px;overflow-x:visible}.browse-dropdown-btn{background-color:#181c25;color:#fff;padding:8px 10px;border:none;border-radius:6px;cursor:pointer;display:flex;justify-content:space-between;align-items:center;font-size:12px;white-space:nowrap;width:100%;overflow:hidden;text-overflow:ellipsis}.browse-dropdown-content{display:none;position:absolute;background-color:#181c25;border:1px solid #334155;border-radius:6px;z-index:10;width:max-content;min-width:200px;max-width:calc(100vw - 20px);max-height:400px;overflow-y:auto;margin-top:4px;padding:10px;box-sizing:border-box;left:0;right:auto}.browse-dropdown.dropdown-right .browse-dropdown-content{left:auto;right:0}.browse-dropdown-content label{display:flex;align-items:center;gap:6px;margin-bottom:6px;font-size:13px;cursor:pointer}.browse-dropdown-content input{margin-right:6px;accent-color:var(--keycolor)}.browse-dropdown.active .browse-dropdown-content{display:block}.browse-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:10px;margin-top:10px}.browse-card{border-radius:8px 8px 0 0;overflow:hidden;transition:transform .2s;margin-bottom:5px}.browse-card:hover{transform:scale(1.02)}.browse-card img{width:100%;height:140px;object-fit:cover;border-radius:8px;background:transparent}.browse-info{text-align:left;padding-left:0}.browse-info h4{font-size:12px;margin:10px 0 5px 0;color:#fff;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}#browse-postGrid.loading::before{content:"Loading&#8230;";grid-column:1/-1;text-align:center;color:#94a3b8}.browse-label{margin:0;padding:0;line-height:1;display:inline-block}.browse-labels{margin-top:4px;display:flex;flex-wrap:nowrap;gap:4px;justify-content:flex-start;align-items:center}.browse-labels > * {flex-shrink: 0;}
.browse-label.type-left{font-size:10px;font-weight:500;color:#47ff67;text-decoration:none;text-transform:uppercase}.browse-sub-label{border:.5px solid rgba(255,165,0,.1);background-color:rgba(255,165,0,.15);color:orange;border-radius:3px;padding:1px 2px;font-weight:500;font-size:8px}.browse-dub-label{border:.5px solid rgba(220,20,60,.1);background-color:rgba(220,20,60,.15);color:crimson;border-radius:3px;padding:1px 2px;font-weight:500;font-size:8px}.browse-az-filter{display:flex;flex-wrap:nowrap;gap:5px;margin:10px 0 0 0;overflow-x:auto;scrollbar-width:none;-ms-overflow-style:none}.browse-az-filter::-webkit-scrollbar{display:none}.browse-az-filter button{background-color:#181c25;color:#fff;border:none;padding:8px 12px;border-radius:4px;font-size:14px;cursor:pointer;transition:background-color .2s}.browse-az-filter button:hover,.browse-az-filter button.active{background-color:var(--keycolor);color:#fff}}
@media (max-width:767px){.head-container{position:fixed;background:none!important;overflow:visible;z-index:0!important}.head-container::before{content:"";position:fixed;top:0;left:0;right:0;height:92px!important;pointer-events:none;z-index:-1!important;background:linear-gradient(to right,transparent 0%,rgba(0,0,0,0.6) 0%,transparent 100%),linear-gradient(to right,transparent 0%,rgba(0,0,0,0.7) 100%),linear-gradient(to bottom,var(--keycolor) 0%,black 90%,black 100%)!important;background-repeat:no-repeat!important;background-size:cover!important}.head-box,.head-menu-fixed{background:transparent!important;position:static!important;z-index:auto!important}}
.ranking-title-container{position:absolute;bottom:-2%;left:4px;right:10px;display:grid;grid-template-columns:auto 1fr;align-items:center;gap:5px;z-index:2}.ranking{font-size:70px;font-weight:900;color:#fff}.image-title{font-size:14px;color:#fff;white-space:normal;overflow:hidden;display:-webkit-box;-webkit-line-clamp:2;-webkit-box-orient:vertical}.image-status{font-size:12px;color:#fff;opacity:.8}@media(max-width:768px){.image-title{font-size:10px}.ranking{font-size:50px}.image-status{font-size:8px;color:#fff;opacity:.8}}.top-overlay{position:absolute;bottom:0;left:0;right:0;height:30%;z-index:1;pointer-events:none}.top-overlay.red{background:linear-gradient(to top,rgba(255,0,0,.5),transparent)}.top-overlay.blue{background:linear-gradient(to top,rgba(0,123,255,.5),transparent)}.top-overlay.violet{background:linear-gradient(to top,rgba(238,130,238,.5),transparent)}.top-overlay.pink{background:linear-gradient(to top,rgba(255,192,203,.5),transparent)}.top-overlay.green{background:linear-gradient(to top,rgba(0,128,0,.5),transparent)}.top-overlay.yellow{background:linear-gradient(to top,rgba(255,255,0,.5),transparent)}.top-overlay.orange{background:linear-gradient(to top,rgba(255,165,0,.5),transparent)}.top-overlay.cyan{background:linear-gradient(to top,rgba(0,255,255,.5),transparent)}.top-overlay.indigo{background:linear-gradient(to top,rgba(75,0,130,.5),transparent)}
