}/* Make all images responsive */
.post img,
.entry-content img,
.widget-content img {
max-width: 100%;
height: auto;
display: block;
margin: auto;
}
/* Control thumbnails (keep uniform look) */
.post-thumbnail img,
.snippet-thumbnail img {
width: 100%;
height: 220px; /* adjust to your design */
object-fit: cover; /* prevents stretching */
border-radius: 8px; /* optional */
}

div.script:
document.querySelectorAll("a.item-group").forEach(link => {
  const relative = link.getAttribute("href");
  // Only update if it starts with "/"
  if (relative.startsWith("/")) {
    link.href = window.location.origin + relative;
  }
});

